#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> boards(n);
    for(int i = 0; i < n; i++) cin >> boards[i];
    int k; cin >> k;

    auto can_paint = [&](int mid){
        int painters = 1;
        int current_work = 0;
        for(int work : boards){
            if(current_work + work > mid){
                painters++;
                current_work = 0;
            }
            current_work += work;
        }
        return painters <= k;
    };

    int low = *max_element(boards.begin(), boards.end());
    int high = accumulate(boards.begin(), boards.end(), 0);
    while(low < high){
        int mid = low + (high - low) / 2;
        if(can_paint(mid)) high = mid;
        else low = mid + 1;
    }
    cout << low << endl;
    return 0;
}
